arguments.command:
cd /app && python3 -c "
import torch
d = torch.load('dataset.pt', map_location='cpu')
print(type(d))
if isinstance(d,dict):
    for k,v in d.items():
        print(k, type(v), tuple(v.shape) if hasattr(v,'shape') else v)
elif isinstance(d,(list,tuple)):
    for i,v in enumerate(d):
        print(i, type(v), tuple(v.shape) if hasattr(v,'shape') else v)
"

